SELECT *
FROM iot_notification_subscription
WHERE tenant_id = #{tenantId}
  AND is_delete = 0

  AND channel_id = #{channelId}


  AND device_group_key = #{deviceGroupKey}

ORDER BY id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM iot_notification_subscription
WHERE tenant_id = #{tenantId}
  AND is_delete = 0

  AND channel_id = #{channelId}


  AND device_group_key = #{deviceGroupKey}

